import React, { useState, useContext } from "react";
import { GeneralContext } from "./GeneralContext";

const BuyActionWindow = ({ mode }) => {
  const { selectedStock, handleCloseBuyWindow, handleAddOrder } =
    useContext(GeneralContext);

  // Defaulting Qty to 1 as seen in your image
  const [qty, setQty] = useState(1);
  const [price, setPrice] = useState(0);

  const handleBuyClick = () => {
    handleAddOrder({
      name: selectedStock,
      qty: parseInt(qty),
      price: parseFloat(price) || 0,
      mode: mode, // This will be "BUY"
    });
    handleCloseBuyWindow(); // Close popup after adding to orders
  };

  return (
    <div className="buy-window-popup" id="buy-window">
      <div className="regular-order">
        <div className="inputs">
          <fieldset>
            <legend>Qty.</legend>
            <input
              type="number"
              onChange={(e) => setQty(e.target.value)}
              value={qty}
            />
          </fieldset>
          <fieldset>
            <legend>Price</legend>
            <input
              type="number"
              step="0.05"
              onChange={(e) => setPrice(e.target.value)}
              value={price}
            />
          </fieldset>
        </div>
      </div>

      <div className="buttons">
        <button className="btn btn-blue" onClick={handleBuyClick}>
          {mode}
        </button>
        <button className="btn btn-grey" onClick={handleCloseBuyWindow}>
          Cancel
        </button>
      </div>
    </div>
  );
};

export default BuyActionWindow;
